#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	
#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000.0f

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

// Helper function to convert fixed-width float string to float on device
// Assumes format like " 12.3" or "123.4" (5 chars)
__device__ float parse_float(const char* str, int len) {
    float result = 0.0f;
    float fraction = 0.0f;
    float divisor = 1.0f;
    int i = 0;
    int sign = 1;
    int found_digit = 0;
    int decimal_found = 0;

    // Skip leading spaces
    while (i < len && str[i] == ' ') {
        i++;
    }

    // Handle sign
    if (i < len && (str[i] == '-' || str[i] == '+')) {
        if (str[i] == '-') sign = -1;
        i++;
    }

    // Integer part
    while (i < len) {
        char c = str[i];
        if (c >= '0' && c <= '9') {
            found_digit = 1;
            result = result * 10.0f + (c - '0');
        } else if (c == '.') {
            decimal_found = 1;
            i++;
            break;
        } else if (c == ' ') {
            if (found_digit) break; // End of number
            i++;
        } else {
            break;
        }
        i++;
    }

    // Fractional part
    if (decimal_found) {
        while (i < len) {
            char c = str[i];
            if (c >= '0' && c <= '9') {
                divisor *= 10.0f;
                fraction += (c - '0') / divisor;
            } else if (c == ' ') {
                break;
            } else {
                break;
            }
            i++;
        }
    }

    return sign * (result + fraction);
}

__global__ void compute_distances(const char* sandbox, float* z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        const char* rec_start = sandbox + (i * REC_LENGTH);
        const char* lat_ptr = rec_start + (LATITUDE_POS - 1);
        const char* lon_ptr = lat_ptr + 5;

        float tmp_lat = parse_float(lat_ptr, 5);
        float tmp_long = parse_float(lon_ptr, 5);

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;

        z[i] = sqrtf(diff_lat * diff_lat + diff_long * diff_long);
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE   *flist,*fp;
    int    i=0,j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long;

    if(argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = (struct neighbor*)malloc(k*sizeof(struct neighbor));

    if(neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for( j = 0 ; k > j ; j++ ) { 
        neighbors[j].dist = OPEN;
    }

    if(fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if(!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z_host = (float *) malloc(REC_WINDOW * sizeof(float));
    float *z_dev = NULL;
    char *sandbox_dev = NULL;

    cudaMalloc(&z_dev, REC_WINDOW * sizeof(float));
    cudaMalloc(&sandbox_dev, REC_LENGTH * REC_WINDOW);

    while(!done) {

        rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if( REC_WINDOW != rec_count ) {
            if(!ferror(flist)) {
                fclose(fp);

                if(feof(flist))
                    done = 1;
                else {
                    if(fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }

                    fp = fopen(dbname, "r");

                    if(!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                    continue; 
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        // Copy data to GPU
        cudaMemcpy(sandbox_dev, sandbox, REC_LENGTH * rec_count, cudaMemcpyHostToDevice);

        // Launch kernel
        int threads_per_block = 256;
        int blocks = (rec_count + threads_per_block - 1) / threads_per_block;
        compute_distances<<<blocks, threads_per_block>>>(sandbox_dev, z_dev, rec_count, target_lat, target_long);
        cudaDeviceSynchronize();

        // Copy results back
        cudaMemcpy(z_host, z_dev, rec_count * sizeof(float), cudaMemcpyDeviceToHost);

        // Sequential update of neighbors (as in original code)
        for( i = 0 ; i < rec_count ; i++ ) {
            float max_dist = -1;
            int max_idx = 0;

            for( j = 0 ; k > j ; j++ ) {
                if( max_dist < neighbors[j].dist ) {
                    max_dist = neighbors[j].dist;
                    max_idx = j;
                }
            }

            if( neighbors[max_idx].dist > z_host[i] ) {
                sandbox[(i+1)*REC_LENGTH-1] = '\0';
                strcpy(neighbors[max_idx].entry, sandbox + i*REC_LENGTH);
                neighbors[max_idx].dist = z_host[i];
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for( j = 0 ; k > j ; j++ ) {
        if( !(OPEN == neighbors[j].dist) )
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    cudaFree(z_dev);
    cudaFree(sandbox_dev);
    free(z_host);
    free(neighbors);

    long long time1 = clock();
    printf("total time : %15.12f s", (float) (time1 - time0) / 1000000);
    return 0;
}
